// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb.evaluation;

import static org.assertj.core.api.Assertions.assertThat;

import org.eclipse.rdf4j.query.algebra.BNodeGenerator;
import org.eclipse.rdf4j.query.algebra.Compare;
import org.eclipse.rdf4j.query.algebra.FunctionCall;
import org.eclipse.rdf4j.query.algebra.Var;
import org.junit.jupiter.api.Test;

class LmdbNativeExpressionRepeatabilityTest {

	@Test
	void deterministicComparisonAndNowAreRepeatable() {
		assertThat(LmdbNativeAggregateFilterCompiler
				.isRepeatable(new Compare(new Var("left"), new Var("right"), Compare.CompareOp.EQ)))
						.isTrue();
		assertThat(LmdbNativeAggregateFilterCompiler.isRepeatable(new FunctionCall("NOW"))).isTrue();
	}

	@Test
	void perRowAndUnknownExpressionsAreNotRepeatable() {
		assertThat(LmdbNativeAggregateFilterCompiler.isRepeatable(new FunctionCall("RAND"))).isFalse();
		assertThat(LmdbNativeAggregateFilterCompiler.isRepeatable(new FunctionCall("UUID"))).isFalse();
		assertThat(LmdbNativeAggregateFilterCompiler.isRepeatable(new FunctionCall("STRUUID"))).isFalse();
		assertThat(LmdbNativeAggregateFilterCompiler.isRepeatable(new BNodeGenerator())).isFalse();
		assertThat(LmdbNativeAggregateFilterCompiler
				.isRepeatable(new FunctionCall("urn:rdf4j:test:unmarked-function")))
						.isFalse();
	}

	@Test
	void encounterOrderReplaySafetyRejectsOpaquePlansAndRetainsRepeatableExtensions() {
		NativeBooleanFilter filter = row -> true;
		assertThat(SlotPlan.encounterOrderReplaySafe(SingletonPlan.INSTANCE)).isTrue();
		assertThat(SlotPlan.encounterOrderReplaySafe(new FilterPlan(SingletonPlan.INSTANCE, filter, 0L))).isTrue();
		assertThat(SlotPlan.encounterOrderReplaySafe(new FilterPlan(SingletonPlan.INSTANCE, filter, -1L))).isFalse();
		assertThat(SlotPlan.encounterOrderReplaySafe(new MultiJoinPlan(
				new SlotPlan[] { SingletonPlan.INSTANCE }, new MaskedFilter[] { new MaskedFilter(filter, -1L) })))
						.isFalse();

		LmdbNativeCompiledInlineId repeatable = new LmdbNativeCompiledInlineId(0L, true, row -> 1L);
		LmdbNativeCompiledInlineId nonRepeatable = new LmdbNativeCompiledInlineId(0L, false, row -> 1L);
		assertThat(SlotPlan.encounterOrderReplaySafe(new ExtensionPlan(SingletonPlan.INSTANCE,
				new CopyBinding[] { CopyBinding.computed(0, repeatable) }))).isTrue();
		assertThat(SlotPlan.encounterOrderReplaySafe(new ExtensionPlan(SingletonPlan.INSTANCE,
				new CopyBinding[] { CopyBinding.computed(0, nonRepeatable) }))).isFalse();
	}
}
